class Solution:
    def findKOr(self, nums: List[int], k: int) -> int:
        bit_count = [0] * 32  # To count set bits for each of the 32 bits
        for num in nums:
            for i in range(32):
                if num & (1 << i):
                    bit_count[i] += 1
        result = 0
        for i in range(32):
            if bit_count[i] >= k:
                result |= (1 << i)
        return result
